// SPDX-License-Identifier: MIT

pragma solidity ^0.8.20;


import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";


/**
 * @title MockFAsset
 * @notice Test version of Flare FAssets for FlareFlow development
 *
 * Simulates:
 * FTestBTC
 * FTestXRP
 *
 * Only for Coston2/demo testing.
 */
contract MockFAsset is ERC20, Ownable {


    constructor(
        string memory name_,
        string memory symbol_
    )
        ERC20(name_, symbol_)
        Ownable(msg.sender)
    {}


    /**
     * @notice Mint test FAssets
     * @dev In production this will be replaced
     * by real FAsset minting through Flare.
     */
    function mint(
        address to,
        uint256 amount
    )
        external
        onlyOwner
    {

        _mint(
            to,
            amount
        );

    }


    /**
     * @notice Burn FAssets
     */
    function burn(
        uint256 amount
    )
        external
    {

        _burn(
            msg.sender,
            amount
        );

    }

}

