 * @notice Simulated yield vault for FlareFlow hackathon demo
 *
 * Accepts:
 * FXRP
 * FBTC
 *
 * Generates simulated APY rewards.
 */
contract MockYieldVault is Ownable {


    IERC20 public immutable asset;


    string public vaultName;


    uint256 public apy;


    uint256 public totalDeposits;


    mapping(address => uint256)
    public deposits;



    constructor(
        address _asset,
        string memory _name,
        uint256 _apy
    )
        Ownable(msg.sender)
    {

        asset = IERC20(_asset);

        vaultName = _name;

        apy = _apy;

    }



    /**
     * @notice Deposit FAssets into vault
     */
    function deposit(
        uint256 amount
    )
        external
    {

        require(
            amount > 0,
            "zero amount"
        );


        asset.transferFrom(
            msg.sender,
            address(this),
            amount
        );


        deposits[msg.sender]
            += amount;


        totalDeposits
            += amount;

    }



    /**
     * @notice Withdraw deposited assets
     */
    function withdraw(
        uint256 amount
    )
        external
    {

        require(
            deposits[msg.sender] >= amount,
            "insufficient balance"
        );


        deposits[msg.sender]
            -= amount;


        totalDeposits
            -= amount;


        asset.transfer(
            msg.sender,
            amount
        );

    }



    /**
     * @notice Simulated earnings
     *
     * Example:
     *
     * Deposit:
     * 1000 XRP
     *
     * APY:
     * 12%
     *
     * Earned:
     * 120 XRP
     */
    function earned(
        address user
    )
        public
        view
        returns(uint256)
    {

        return
            (deposits[user] * apy) / 100;

    }



    function getBalance(
        address user
    )
        external
        view
        returns(uint256)
    {

        return deposits[user];

    }



    function updateAPY(
        uint256 newAPY
    )
        external
        onlyOwner
    {

        apy = newAPY;

    }


}

